/* ─── Animated Data Dot ─────────────────────────────────────── */
function DataDot({ pathRef }: { pathRef: React.RefObject<SVGPathElement | null> }) {
    const dotRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const path = pathRef.current;
        if (!path) return;

        const totalLength = path.getTotalLength();
        let forward = true;
        let progress = 0;
        let animId: number;

        const animate = () => {
            progress += forward ? 0.004 : -0.004;
            if (progress >= 1) { forward = false; progress = 1; }
            if (progress <= 0) { forward = true; progress = 0; }

            const point = path.getPointAtLength(progress * totalLength);
            if (dotRef.current) {
                dotRef.current.style.transform = `translate(${point.x - 5}px, ${point.y - 5}px)`;
            }
            animId = requestAnimationFrame(animate);
        };
        animId = requestAnimationFrame(animate);
        return () => cancelAnimationFrame(animId);
    }, [pathRef]);

    return (
        <div
            ref={dotRef}
            className="absolute left-0 top-0 h-[8px] w-[8px] rounded-full bg-cyan-400 shadow-[0_0_12px_3px_rgba(34,211,238,0.8)]"
            style={{ willChange: 'transform' }}
        />
    );
}

